/**
 * GraphicWrapper — shared shell for every composition.
 * Handles: brand background, font, spring scale-in, opacity dissolve-out.
 *
 * Banding fix: no blur is used. Instead, gradient + content fade out together
 * via opacity. Once they're gone the flat background clears over 8 frames,
 * leaving a fully transparent frame — no blur, no banding artefacts.
 */
import React from "react";
import {
  AbsoluteFill,
  Easing,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { loadFont } from "@remotion/google-fonts/Montserrat";
import { BG_GRADIENT, COLOR, SPRING } from "./brand";

const { fontFamily } = loadFont("normal", {
  weights: ["400", "600", "700", "800"],
  subsets: ["latin"],
});

export const GraphicWrapper: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  // Out: 6-frame content fade (0.2s) + 8-frame bg clear = 14 frames total
  const dissolveStart = durationInFrames - 14;

  // ── Gradient + content fade out — ease-in (accelerates to invisible) ──────
  const contentOp = interpolate(
    frame,
    [dissolveStart, dissolveStart + 6],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp", easing: Easing.in(Easing.quad) }
  );

  // ── Flat background clears over 8 frames after content is gone ───────────
  const bgOp = interpolate(
    frame,
    [dissolveStart + 6, dissolveStart + 14],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  // ── Content fade-in (0.3s) — ease-out cubic (snappy arrival) ─────────────
  const fadeIn = interpolate(frame, [0, 9], [0, 1], {
    extrapolateRight: "clamp",
    easing: Easing.out(Easing.cubic),
  });
  const scale = spring({
    frame,
    fps,
    from: 0.84,
    to: 1,
    config: SPRING.snappy,
  });

  return (
    <AbsoluteFill
      style={{
        background: COLOR.bgCenter,
        fontFamily,
        opacity: bgOp,
      }}
    >
      {/* Gradient + content — fade out together, no blur */}
      <div style={{ position: "absolute", inset: 0, opacity: contentOp }}>

        {/* Gradient overlay */}
        <div
          style={{
            position: "absolute",
            inset: 0,
            background: BG_GRADIENT,
          }}
        />

        {/* Content */}
        <div
          style={{
            position: "absolute",
            inset: 0,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            transform: `scale(${scale})`,
            opacity: fadeIn,
          }}
        >
          {children}
        </div>

      </div>
    </AbsoluteFill>
  );
};

/**
 * Brand Tokens — single source of truth for all motion graphics.
 * Update here and every composition picks it up automatically.
 */

// ── Colours ───────────────────────────────────────────────────────────────
export const COLOR = {
  // Background gradient (radial, centre → edge)
  bgCenter:  "#e0e1dd",
  bgMid:     "#6b6b6b",
  bgEdge:    "#222222",

  // Ring accents
  ringPrimary:   "#415a77",   // steel blue  — main data ring
  ringSecondary: "#c2a46d",   // warm gold   — supporting ring
  ringTrack:     "rgba(0,0,0,0.08)",

  // Typography
  textPrimary:   "#1D1D1F",
  textSecondary: "rgba(29,29,31,0.45)",
  textMuted:     "rgba(29,29,31,0.6)",
  textAccent:    "#415a77",   // matches ringPrimary

  // Glow
  glowPrimary: "rgba(65,90,119,0.7)",
} as const;

// ── Background gradient string ─────────────────────────────────────────────
export const BG_GRADIENT =
  `radial-gradient(ellipse at 50% 50%, ${COLOR.bgCenter} 0%, ${COLOR.bgCenter} 16%, ${COLOR.bgMid} 60%, ${COLOR.bgEdge} 100%)`;

// ── Typography ─────────────────────────────────────────────────────────────
export const FONT_WEIGHT = {
  regular:   400,
  semibold:  600,
  bold:      700,
  extraBold: 800,  // ← brand standard — use this for all display text
} as const;

// ── Animation defaults ─────────────────────────────────────────────────────
export const SPRING = {
  snappy:  { damping: 15, stiffness: 220, mass: 1 },
  bouncy:  { damping: 12, stiffness: 280, mass: 0.8 },
  smooth:  { damping: 14, stiffness: 200, mass: 1 },
} as const;

export const DURATION = {
  short:    3,   // seconds — quick stat/callout graphic
  medium:   8,   // seconds — explanation graphic
  long:     15,  // seconds — full timeline breakdown
} as const;

// ── SVG ring geometry ──────────────────────────────────────────────────────
export const RING = {
  r:           78,
  strokeWidth: 34,
  get C()      { return 2 * Math.PI * this.r; },
} as const;

